const regionSelect = document.getElementById('regionSelect');
const locationSelect = document.getElementById('locationSelect');
const nextBtn = document.getElementById('nextBtn');
const addRowBtn = document.getElementById('addRowBtn');
const saveBtn = document.getElementById('saveBtn');
const resetBtn = document.getElementById('resetBtn');
const tableSection = document.getElementById('tableSection');
const emptyState = document.getElementById('emptyState');
const selectionInfo = document.getElementById('selectionInfo');
const tableHead = document.querySelector('#dataTable thead');
const tableBody = document.querySelector('#dataTable tbody');
const selectedRegionText = document.getElementById('selectedRegionText');
const selectedLocationText = document.getElementById('selectedLocationText');
const selectedSheetText = document.getElementById('selectedSheetText');
const tableNote = document.getElementById('tableNote');
const locationCount = document.getElementById('locationCount');
const appCard = document.getElementById('appCard');
let activeRowIds = new Set();
let activeSourceMode = 'cloud';

function toKeyPart(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '') || 'default';
}

function getRowsCollection(region, location) {
  return collection(db, 'nrwData', toKeyPart(region), 'locations', toKeyPart(location), 'rows');
}

async function getSavedRows(region, location, config) {
  const fallbackRows = getLocalSavedRows(region, location);
  try {
    const snapshot = await getDocs(getRowsCollection(region, location));
    const docs = snapshot.docs.map(docSnap => {
      const data = docSnap.data() || {};
      const rowData = Array.isArray(data.rowData) ? data.rowData : [];
      return {
        id: docSnap.id,
        rowData: rowData,
        createdAtMs: data.createdAt && typeof data.createdAt.toMillis === 'function' ? data.createdAt.toMillis() : 0,
        updatedAtMs: data.updatedAt && typeof data.updatedAt.toMillis === 'function' ? data.updatedAt.toMillis() : 0
      };
    }).sort((a, b) => (a.createdAtMs || a.updatedAtMs || 0) - (b.createdAtMs || b.updatedAtMs || 0));

    activeSourceMode = 'cloud';
    if (docs.length) {
      const cloudRows = docs.map(item => ({ id: item.id, values: item.rowData }));
      setLocalSavedRows(region, location, cloudRows.map(item => item.values));
      return cloudRows;
    }

    if (fallbackRows.length) {
      return fallbackRows.map(values => ({ id: '', values }));
    }

    return [];
  } catch (error) {
    console.error('Firestore load failed:', error);
    activeSourceMode = 'local';
    return fallbackRows.map(values => ({ id: '', values }));
  }
}

async function saveRowsToDatabase(region, location, config, rowPayloads) {
  const rowsRef = getRowsCollection(region, location);
  const nextIds = new Set();

  try {
    for (const row of rowPayloads) {
      const rowId = row.id || (crypto.randomUUID ? crypto.randomUUID() : `row-${Date.now()}-${Math.random().toString(16).slice(2)}`);
      nextIds.add(rowId);

      const payload = {
        region,
        location,
        sheetName: config?.sheetName || '',
        headers: Array.isArray(config?.headers) ? config.headers : [],
        rowData: row.values,
        updatedAt: serverTimestamp()
      };

      if (!row.id) {
        payload.createdAt = serverTimestamp();
      }

      await setDoc(doc(rowsRef, rowId), payload, { merge: true });
      row.id = rowId;
    }

    for (const existingId of activeRowIds) {
      if (!nextIds.has(existingId)) {
        await deleteDoc(doc(rowsRef, existingId));
      }
    }

    activeRowIds = nextIds;
    activeSourceMode = 'cloud';
    setLocalSavedRows(region, location, rowPayloads.map(item => item.values));
    return { ok: true, mode: 'cloud' };
  } catch (error) {
    console.error('Firestore save failed:', error);
    activeSourceMode = 'local';
    setLocalSavedRows(region, location, rowPayloads.map(item => item.values));
    activeRowIds = new Set(rowPayloads.map(item => item.id).filter(Boolean));
    return { ok: true, mode: 'local', error };
  }
}


function populateRegions() {
  Object.keys(regionLocations).forEach(region => {
    const option = document.createElement('option');
    option.value = region;
    option.textContent = region;
    regionSelect.appendChild(option);
  });
}

function populateLocations(region) {
  locationSelect.innerHTML = '<option value="">Select location</option>';
  const locations = regionLocations[region] || [];
  if (!region || !locations.length) {
    locationSelect.disabled = true;
    nextBtn.disabled = true;
    locationCount.textContent = '';
    return;
  }
  locations.forEach(location => {
    const option = document.createElement('option');
    option.value = location;
    option.textContent = location;
    locationSelect.appendChild(option);
  });
  locationSelect.disabled = false;
  nextBtn.disabled = true;
  
}

function clearTable() {
  tableHead.innerHTML = '';
  tableBody.innerHTML = '';
}

function getStorageKey(region, location) {
  return `nrwSavedRows::${region}::${location}`;
}

function getLocalSavedRows(region, location) {
  try {
    return JSON.parse(localStorage.getItem(getStorageKey(region, location)) || '[]');
  } catch (error) {
    return [];
  }
}

function setLocalSavedRows(region, location, rows) {
  localStorage.setItem(getStorageKey(region, location), JSON.stringify(rows));
}

function showStatus(message) {
  let toast = document.getElementById('statusToast');
  if (!toast) {
    toast = document.createElement('div');
    toast.id = 'statusToast';
    toast.className = 'status-toast';
    document.body.appendChild(toast);
  }
  toast.textContent = message;
  toast.classList.add('show');
  clearTimeout(showStatus._timer);
  showStatus._timer = setTimeout(() => toast.classList.remove('show'), 1800);
}

function collectTableRows() {
  return Array.from(tableBody.querySelectorAll('tr')).map(tr => ({
    id: tr.dataset.rowId || '',
    values: Array.from(tr.querySelectorAll('input')).map(input => input.value.trim())
  }));
}

function setRowEditable(tr, editable) {
  tr.dataset.editing = editable ? 'true' : 'false';
  tr.querySelectorAll('input').forEach(input => {
    input.disabled = !editable;
  });
  const editBtn = tr.querySelector('.edit-row-btn');
  if (editBtn) {
    editBtn.textContent = editable ? 'Done' : 'Edit';
    editBtn.className = editable ? 'btn btn-sm btn-primary edit-row-btn' : 'btn btn-sm btn-outline-primary edit-row-btn';
  }
}

function attachRowActions(tr) {
  const editBtn = tr.querySelector('.edit-row-btn');
  const removeBtn = tr.querySelector('.remove-row-btn');

  editBtn.addEventListener('click', () => {
    const isEditing = tr.dataset.editing === 'true';
    setRowEditable(tr, !isEditing);
  });

  removeBtn.addEventListener('click', () => {
    tr.remove();
  });
}

function addTableRow(headers, values = [], options = {}) {
  const tr = document.createElement('tr');
  const isSavedRow = options.saved === true;
  tr.dataset.rowId = options.rowId || '';

  headers.forEach((header, index) => {
    const td = document.createElement('td');
    const input = document.createElement('input');
    input.type = header.toLowerCase().includes('date') ? 'date' : 'text';
    input.className = 'form-control form-control-sm';
    input.value = values[index] || '';
    input.disabled = isSavedRow;
    td.appendChild(input);
    tr.appendChild(td);
  });

  const actionTd = document.createElement('td');
  actionTd.className = 'text-center';
  actionTd.innerHTML = `
    <div class="table-actions">
      <button type="button" class="btn btn-sm ${isSavedRow ? 'btn-outline-primary' : 'btn-primary'} edit-row-btn">${isSavedRow ? 'Edit' : 'Done'}</button>
      <button type="button" class="btn btn-sm btn-outline-danger remove-row-btn">Remove</button>
    </div>
  `;
  tr.appendChild(actionTd);

  tableBody.appendChild(tr);
  tr.dataset.editing = isSavedRow ? 'false' : 'true';
  attachRowActions(tr);
}

function formatWrappedHeader(header) {
  const clean = String(header || '').replace(/\s+/g, ' ').trim();
  if (!clean) return '';

  const explicitBreaks = clean
    .replace(/\s*\/\s*/g, ' / ')
    .replace(/\s*-\s*/g, '<br>')
    .replace(/\s*\(\s*/g, '<br>(');

  if (explicitBreaks.includes('<br>')) {
    return explicitBreaks.replace(/(<br>)(Major|Minor|Service|Status|Pump|WTP|OIC)/g, '$1$2');
  }

  const words = clean.split(' ');
  if (words.length <= 2) return clean;

  const targetLines = words.length >= 7 ? 3 : 2;
  const chunkSize = Math.ceil(words.length / targetLines);
  const lines = [];
  for (let i = 0; i < words.length; i += chunkSize) {
    lines.push(words.slice(i, i + chunkSize).join(' '));
  }
  return lines.join('<br>');
}

async function renderTable(region, location) {
  const dataKey = spreadsheetAliases[location] || location;
  const config = spreadsheetData[region]?.[dataKey];
  const dataTable = tableHead.closest('table');
  const wrappedRegions = new Set(['Central East', 'Matale', 'Central South', 'Central North']);
  const useWrappedLayout = wrappedRegions.has(region);

  dataTable.classList.toggle('wrapped-layout', useWrappedLayout);
  selectedRegionText.textContent = region || '-';
  selectedLocationText.textContent = location || '-';
  selectedSheetText.textContent = config ? config.sheetName : 'Pending';
  selectionInfo.classList.remove('d-none');
  appCard.classList.add('compact-mode');
  activeRowIds = new Set();
  clearTable();

  if (!config) {
    tableSection.classList.add('d-none');
    emptyState.classList.remove('d-none');
    emptyState.innerHTML = `<p class="mb-0"><strong>${location}</strong> is kept empty for now. Send that sheet later and I will connect the columns and rows.</p>`;
    return;
  }

  const headerRow = document.createElement('tr');
  config.headers.forEach(header => {
    const th = document.createElement('th');
    if (useWrappedLayout) {
      th.innerHTML = `<span class="header-wrap">${formatWrappedHeader(header)}</span>`;
    } else {
      th.textContent = header || '';
    }
    headerRow.appendChild(th);
  });
  const actionTh = document.createElement('th');
  actionTh.textContent = 'Action';
  headerRow.appendChild(actionTh);
  tableHead.appendChild(headerRow);

  const savedRows = await getSavedRows(region, location, config);
  activeRowIds = new Set(savedRows.map(row => row.id).filter(Boolean));
  savedRows.forEach(row => addTableRow(config.headers, row.values, { saved: true, rowId: row.id }));

  tableNote.textContent = savedRows.length
    ? `${savedRows.length} saved row(s) loaded for ${location}.`
    : `Cloud save is ready for ${location}.`;
  tableSection.classList.remove('d-none');
  emptyState.classList.add('d-none');
}

regionSelect.addEventListener('change', () => {
  populateLocations(regionSelect.value);
  activeRowIds = new Set();
  activeRowIds = new Set();
  clearTable();
  tableSection.classList.add('d-none');
  selectionInfo.classList.add('d-none');
  appCard.classList.remove('compact-mode');
  emptyState.classList.remove('d-none');
  emptyState.innerHTML = '<p class="mb-0">Select a region and location, then click <strong>Next</strong>.</p>';
});

locationSelect.addEventListener('change', () => {
  nextBtn.disabled = !(regionSelect.value && locationSelect.value);
});

nextBtn.addEventListener('click', async () => {
  await renderTable(regionSelect.value, locationSelect.value);
});

addRowBtn.addEventListener('click', () => {
  const region = regionSelect.value;
  const location = locationSelect.value;
  const dataKey = spreadsheetAliases[location] || location;
  const headers = spreadsheetData[region]?.[dataKey]?.headers;
  if (!headers) return;
  addTableRow(headers);
});

saveBtn.addEventListener('click', async () => {
  const region = regionSelect.value;
  const location = locationSelect.value;
  if (!region || !location) return;

  const dataKey = spreadsheetAliases[location] || location;
  const config = spreadsheetData[region]?.[dataKey];
  if (!config) return;

  const allRows = collectTableRows();
  const rows = allRows.filter(row => row.values.some(value => value !== ''));
  const result = await saveRowsToDatabase(region, location, config, rows);

  let keptIndex = 0;
  tableBody.querySelectorAll('tr').forEach(tr => {
    const hasData = Array.from(tr.querySelectorAll('input')).some(input => input.value.trim() !== '');
    if (!hasData) {
      tr.remove();
      return;
    }

    tr.dataset.rowId = rows[keptIndex]?.id || tr.dataset.rowId || '';
    keptIndex += 1;
    setRowEditable(tr, false);
  });

  tableNote.textContent = rows.length
    ? `${rows.length} row(s) saved for ${location} ${result.mode === 'cloud' ? 'in Firestore.' : 'in this browser only.'}`
    : `No rows are saved for ${location} right now.`;

  showStatus(result.mode === 'cloud' ? 'Rows saved to Firestore' : 'Firestore unavailable - saved in browser');
});

resetBtn.addEventListener('click', () => {
  regionSelect.value = '';
  locationSelect.innerHTML = '<option value="">Select location</option>';
  locationSelect.disabled = true;
  nextBtn.disabled = true;
  locationCount.textContent = '';
  activeRowIds = new Set();
  clearTable();
  tableSection.classList.add('d-none');
  selectionInfo.classList.add('d-none');
  appCard.classList.remove('compact-mode');
  emptyState.classList.remove('d-none');
  emptyState.innerHTML = '<p class="mb-0">Select a region and location, then click <strong>Next</strong>.</p>';
});

populateRegions();

window.addEventListener('load', () => {
  setTimeout(() => {
    document.getElementById('loadingScreen').style.display = 'none';
    document.getElementById('mainContent').classList.remove('d-none');
  }, 2000);
});
